/**
 * Email template + quality gate for the outreach pipeline.
 *
 * v3 template (2026-04-15 iteration after the first live send): inline
 * "Hi {firstName} - " greeting on the same line as the hook, soft
 * subscribe invite on its own line with the bare fundopshq.com link, no
 * "no thanks" unsub line (monitor still honors any reply-with-stop via
 * regex). No em dashes, "my morning brief" phrasing, Founder & Host sig.
 *
 * The template is STATIC. Only the hook sentence (generated by
 * anthropic-client.ts) and the first name vary per email. Do not loosen
 * this — every bug we find in a draft that goes out becomes a blast-radius
 * incident, and the quality gate below can't verify freeform prose.
 */

import type { ComposedEmail, QualityGateResult } from './types'
import { shortenFirmName } from './candidates'

export function composeEmail(params: {
  firstName: string
  firmName: string
  hook: string
}): ComposedEmail {
  const { firstName, firmName, hook } = params
  const firmShort = shortenFirmName(firmName)
  const subject = `Covered ${firmShort} today`

  // Ensure the hook ends with a period (the Anthropic prompt requests
  // this but we belt-and-suspenders it here).
  const hookTrimmed = hook.trim().replace(/[.!?]*$/, '')

  const body = [
    `Hi ${firstName} - ${hookTrimmed}. It made today's edition of FundOps Daily, my morning brief for GPs, LPs, and fund service providers.`,
    '',
    `If you're interested in seeing similar news or subscribing to the newsletter, you can visit fundopshq.com.`,
    '',
    'Danny',
    'Founder & Host, FundOpsHQ',
  ].join('\n')

  return { subject, body }
}

/**
 * Hard quality gate. Runs AFTER composeEmail() and BEFORE sendGmail().
 * Every check is a hard failure — if any fire, drop the candidate and
 * log a cold_outreach_sent row with status='skipped' and the reason.
 *
 * Blast-radius logic: we'd rather send 7 clean emails than 10 including
 * one that embarrasses Danny. The full batch can run light and still
 * provide daily drip.
 */
export function qualityGate(body: string, subject: string): QualityGateResult {
  // 1. Word count cap. New template body is ~50 words before the hook;
  // hook adds another 15-25, so 80 is the ceiling with headroom.
  const words = body.trim().split(/\s+/).filter(Boolean).length
  if (words > 80) return { ok: false, reason: 'over_word_cap' }

  // 2. Required content — fundopshq.com link somewhere in the body.
  if (!body.includes('fundopshq.com')) {
    return { ok: false, reason: 'missing_link' }
  }

  // 3. Required content — signature block with title.
  if (!body.includes('Founder & Host, FundOpsHQ')) {
    return { ok: false, reason: 'missing_signature' }
  }

  // 4. No em/en dashes (Danny flagged these as not his style).
  if (body.includes('\u2014') || body.includes('\u2013')) {
    return { ok: false, reason: 'em_dash' }
  }

  // 5. No "I write" (Danny made FundOps Daily but doesn't write it —
  // using that phrasing reads as disingenuous).
  if (/\bI\s+write\b/i.test(body)) {
    return { ok: false, reason: 'disingenuous_phrasing' }
  }

  // 6. Greeting present — must be "Hi " followed by a non-space character
  // so we block the empty-first-name "Hi  - Saw..." form.
  if (!/^Hi \S/.test(body)) {
    return { ok: false, reason: 'missing_greeting' }
  }

  // 7. Subject shape.
  if (!subject.startsWith('Covered ')) {
    return { ok: false, reason: 'wrong_subject_prefix' }
  }
  if (!subject.endsWith(' today')) {
    return { ok: false, reason: 'wrong_subject_suffix' }
  }

  return { ok: true }
}

/**
 * Helper: count words the same way the quality gate does. Exposed so the
 * Anthropic hook generator can self-check output length before it gets
 * composed into the full body.
 */
export function wordCount(text: string): number {
  return text.trim().split(/\s+/).filter(Boolean).length
}
